%[text] ## Lab 3
%[text] ### Harmonic response of second-order rectilinear systems
%%
%[text] #### Harware parameters
T = 0.001; % sampling time (change to fit your experiment)

r = 0.01; % pinion gear radius [m]

Kt = 0.028; % torque constant for the EMB-AM2 actuator [Nm/A]

motor_eff = 1.0; % system efficiency (change to match your plant)

Kt = Kt*motor_eff; % including efficiency, actual Kt used in Simulink
%[text] #### Simulation Parameters
k_sim = 0;
b_sim = 0;
%%
%[text] ### Experiment 1: Sine-Sweep Tests
S = 10;             % simulation duration time

t = 0:T:S;          % total time
y = zeros(size(t)); % output

t1 = 10;

f0 = 1;
f1 = 5;

amp = 2;

y = amp .* chirp(t, f0, t1, f1);
plot(t, y) %[output:7701ae3a]

% Add labels and title to the plot
xlabel('Time (s)'); %[output:7701ae3a]
ylabel('Output Amplitude'); %[output:7701ae3a]
title('Chirp Signal Response'); %[output:7701ae3a]
grid on; %[output:7701ae3a]


sim_input = timeseries(y', t');

% Define parameters
model_name = 'MSE_PLANT';

% Load and configure for Real-Time / External mode
load_system(model_name);
set_param(model_name, 'SimulationMode', 'external');

set_param(model_name, 'StopTime', num2str(S));

% Execute
set_param(model_name,'SimulationCommand','start')
%%
%% PLOTTING - Input Force

plot(rt_time, f_input,'LineWidth',2); %[output:3042eb8d]
title('Input Force vs. Time'); %[output:3042eb8d]
xlabel('Time [s]'); %[output:3042eb8d]
ylabel('Force [N]'); %[output:3042eb8d]
legend('Input Force'); %[output:3042eb8d]
grid on; %[output:3042eb8d]

%% PLOTTING - Position for both Carts
plot(rt_time, cart1_position*100, rt_time, cart2_position*100,'LineWidth',2); %[output:8981c37b]
title('Position vs. Time'); %[output:8981c37b]
xlabel('Time [s]'); %[output:8981c37b]
ylabel('Position [cm]'); %[output:8981c37b]
legend('Cart1','Cart2'); %[output:8981c37b]
grid on; %[output:8981c37b]

plot(f_input, cart1_position, 'LineWidth', 2); %[output:96efb16d]
title('Force vs displacement'); %[output:96efb16d]
xlabel('Force (N)') %[output:96efb16d]
ylabel('displacement') %[output:96efb16d]
grid on; %[output:96efb16d]

plot(rt_time, cart1_velocity*100, rt_time, cart2_velocity*100, 'LineWidth', 2); %[output:8c9aaba3]
title('Velocity vs Time'); %[output:8c9aaba3]
xlabel('Time [s]') %[output:8c9aaba3]
ylabel('Velocity [cm/s]') %[output:8c9aaba3]
grid on; %[output:8c9aaba3]

